              "content": "// Copyright 2024 JoyLee (@itarze)\n// SPDX-License-Identifier: GPL-2.0-or-later\n\n#ifdef GPIO_UART_ENABLE\n\n#    include \"quantum.h\"\n#    include <stdarg.h>\n\n#    define DEALY_NS_250()    wait_cpuclock(CPU_CLOCK / 1000000L / 4)\n\n#    define GPIO_UART_DELAY() delay(26) // CPU_CLOCK Set to 72MHz BOUND 115200. In other cases, please modify it yourself.\n\n#    define MAX_FILLER        11\n\n#    ifndef GPIO_UART_TX_PIN\n#        define GPIO_UART_TX_PIN A13 // swdio\n#    endif\n\nstatic void delay(uint32_t times) {\n    while (times--) {\n        DEALY_NS_250();\n    }\n}\n\nvoid iprint_init(void) {\n    setPinOutput(GPIO_UART_TX_PIN);\n    writePinHigh(GPIO_UART_TX_PIN);\n}\n\nvoid gpiouart_send(uint8_t data) {\n    chSysLock();\n\n    writePin(GPIO_UART_TX_PIN, 0);\n    GPIO_UART_DELAY();\n\n    for (uint8_t i = 0; i < 8; i++) {\n        if ((data >> i) & 0x01) {\n            writePin(GPIO_UART_TX_PIN, 1);\n            GPIO_UART_DELAY();\n        } else {\n            writePin(GPIO_UART_TX_PIN, 0);\n            GPIO_UART_DELAY();\n        }\n    }\n\n    writePin(GPIO_UART_TX_PIN, 1);\n    GPIO_UART_DELAY();\n\n    chSysUnlock();\n}\n\nstatic char *long_to_string_with_divisor(char *p,\n                                         long num,\n                                         unsigned radix,\n                                         long divisor) {\n    int i;\n    char *q;\n    long l, ll;\n\n    l = num;\n    if (divisor == 0) {\n        ll = num;\n    } else {\n        ll = divisor;\n    }\n\n    q = p + MAX_FILLER;\n    do {\n        i = (int)(l % radix);\n        i += '0';\n        if (i > '9') {\n            i += 'A' - '0' - 10;\n        }\n        *--q = i;\n        l /= radix;\n    } while ((ll /= radix) != 0);\n\n    i = (int)(p + MAX_FILLER - q);\n    do {\n        *p++ = *q++;\n    } while (--i);\n\n    return p;\n}\n\nstatic char *ch_ltoa(char *p, long num, unsigned radix) {\n    return long_to_string_with_divisor(p, num, radix, 0);\n}\n\nstatic int ivprintf(const char *fmt, va_list ap) {\n    char *p, *s, c, filler;\n    int i, precision, width;\n    int n = 0;\n    bool is_long, left_align, do_sign;\n    long l;\n#    if CHPRINTF_USE_FLOAT\n    float f;\n    char tmpbuf[2 * MAX_FILLER + 1];\n#    else\n    char tmpbuf[MAX_FILLER + 1];\n#    endif\n\n    while (true) {\n        c = *fmt++;\n        if (c == 0) {\n            return n;\n        }\n\n        if (c != '%') {\n            gpiouart_send((uint8_t)c);\n            n++;\n            continue;\n        }\n\n        p = tmpbuf;\n        s = tmpbuf;\n\n        /* Alignment mode.*/\n        left_align = false;\n        if (*fmt == '-') {\n            fmt++;\n            left_align = true;\n        }\n\n        /* Sign mode.*/\n        do_sign = false;\n        if (*fmt == '+') {\n            fmt++;\n            do_sign = true;\n        }\n\n        /* Filler mode.*/\n        filler = ' ';\n        if (*fmt == '0') {\n            fmt++;\n            filler = '0';\n        }\n\n        /* Width modifier.*/\n        if (*fmt == '*') {\n            width = va_arg(ap, int);\n            ++fmt;\n            c = *fmt++;\n        } else {\n            width = 0;\n            while (true) {\n                c = *fmt++;\n                if (c == 0) {\n                    return n;\n                }\n                if (c >= '0' && c <= '9') {\n                    c -= '0';\n                    width = width * 10 + c;\n                } else {\n                    break;\n                }\n            }\n        }\n\n        /* Precision modifier.*/\n        precision = 0;\n        if (c == '.') {\n            c = *fmt++;\n            if (c == 0) {\n                return n;\n            }\n            if (c == '*') {\n                precision = va_arg(ap, int);\n                c         = *fmt++;\n            } else {\n                while (c >= '0' && c <= '9') {\n                    c -= '0';\n                    precision = precision * 10 + c;\n                    c         = *fmt++;\n                    if (c == 0) {\n                        return n;\n                    }\n                }\n            }\n        }\n\n        /* Long modifier.*/\n        if (c == 'l' || c == 'L') {\n            is_long = true;\n            c       = *fmt++;\n            if (c == 0) {\n                return n;\n            }\n        } else {\n            is_long = (c >= 'A') && (c <= 'Z');\n        }\n\n        /* Command decoding.*/\n        switch (c) {\n            case 'c':\n                filler = ' ';\n                *p++   = va_arg(ap, int);\n                break;\n            case 's':\n                filler = ' ';\n                if ((s = va_arg(ap, char *)) == 0) {\n                    s = \"(null)\";\n                }\n                if (precision == 0) {\n                    precision = 32767;\n                }\n                for (p = s; *p && (--precision >= 0); p++)\n                    ;\n                break;\n            case 'D':\n            case 'd':\n            case 'I':\n            case 'i':\n                if (is_long) {\n                    l = va_arg(ap, long);\n                } else {\n                    l = va_arg(ap, int);\n                }\n                if (l < 0) {\n                    *p++ = '-';\n                    l    = -l;\n                } else if (do_sign) {\n                    *p++ = '+';\n                }\n                p = ch_ltoa(p, l, 10);\n                break;\n#    if CHPRINTF_USE_FLOAT\n            case 'f':\n                f = (float)va_arg(ap, double);\n                if (f < 0) {\n                    *p++ = '-';\n                    f    = -f;\n                } else {\n                    if (do_sign) {\n                        *p++ = '+';\n                    }\n                }\n                p = ftoa(p, f, precision);\n                break;\n#    endif\n            case 'X':\n            case 'x':\n            case 'P':\n            case 'p':\n                c = 16;\n                goto unsigned_common;\n            case 'U':\n            case 'u':\n                c = 10;\n                goto unsigned_common;\n            case 'O':\n            case 'o':\n                c = 8;\n            unsigned_common:\n                if (is_long) {\n                    l = va_arg(ap, unsigned long);\n                } else {\n                    l = va_arg(ap, unsigned int);\n                }\n                p = ch_ltoa(p, l, c);\n                break;\n            default:\n                *p++ = c;\n                break;\n        }\n        i = (int)(p - s);\n        if ((width -= i) < 0) {\n            width = 0;\n        }\n        if (left_align == false) {\n            width = -width;\n        }\n        if (width < 0) {\n            if ((*s == '-' || *s == '+') && filler == '0') {\n                gpiouart_send((uint8_t)*s++);\n                n++;\n                i--;\n            }\n            do {\n                gpiouart_send((uint8_t)filler);\n                n++;\n            } while (++width != 0);\n        }\n        while (--i >= 0) {\n            gpiouart_send((uint8_t)*s++);\n            n++;\n        }\n\n        while (width) {\n            gpiouart_send((uint8_t)filler);\n            n++;\n            width--;\n        }\n    }\n}\n\nint iprintf(const char *fmt, ...) {\n    va_list ap;\n    int formatted_bytes;\n\n    va_start(ap, fmt);\n    formatted_bytes = ivprintf(fmt, ap);\n    va_end(ap);\n\n    return formatted_bytes;\n}\n#endif\n"
