                          "content": "{\n  \"name\": \"MonsGeek M1 V5\",\n  \"vendorId\": \"0xFFFE\",\n  \"productId\": \"0x0005\",\n  \"lighting\": \"vialrgb\",\n  \"matrix\": { \"rows\": 6, \"cols\": 15 },\n  \"layouts\": {\n    \"labels\": [\n      \"ISO Enter\",\n      \"Split Left Shift\"       \n    ],\n    \"keymap\":[\n      [\n        {\"x\": 15, \"c\": \"#AAAAAA\"},\n        \"0,0\\n\\n\\n\\n\\n\\n\\n\\n\\ne\",\n        \"0,1\\n\\n\\n\\n\\n\\n\\n\\n\\ne\"\n      ],\n      [\n        {\"c\": \"#777777\"},\n        \"0,0\",\n        {\"x\": 0.25, \"c\": \"#AAAAAA\"},\n        \"0,1\", \"0,2\", \"0,3\", \"0,4\",\n        {\"x\": 0.25},\n        \"0,5\", \"0,6\", \"0,7\", \"0,8\",\n        {\"x\": 0.25},\n        \"0,9\", \"0,10\", \"0,11\", \"0,12\",\n        {\"x\": 0.25},\n        \"0,13\",\n        {\"x\": 0.5},\n        \"0,14\"\n      ],\n      [\n        {\"y\": 0.25},\n        \"1,0\\n`\",\n        {\"c\": \"#cccccc\"},\n        \"1,1\", \"1,2\", \"1,3\", \"1,4\", \"1,5\", \"1,6\", \"1,7\", \"1,8\", \"1,9\", \"1,10\", \"1,11\", \"1,12\",\n        {\"c\": \"#AAAAAA\", \"w\": 2},\n        \"1,13\",\n        {\"x\": 0.5},\n        \"1,14\"\n      ],\n      [\n        {\"w\": 1.5},\n        \"2,0\",\n        {\"c\": \"#cccccc\"},\n        \"2,1\", \"2,2\", \"2,3\", \"2,4\", \"2,5\", \"2,6\", \"2,7\", \"2,8\", \"2,9\", \"2,10\", \"2,11\", \"2,12\",\n        {\"c\": \"#AAAAAA\", \"w\": 1.5},\n        \"2,13\\n\\n\\n0,0\",\n        {\"x\": 0.5},\n        \"2,14\",\n        {\"x\": 1.25, \"c\": \"#777777\", \"w\": 1.25, \"h\": 2, \"w2\": 1.5, \"h2\": 1, \"x2\": -0.25},\n        \"3,13\\n\\n\\n0,1\"\n      ],\n      [\n        {\"c\": \"#AAAAAA\", \"w\": 1.75},\n        \"3,0\",\n        {\"c\": \"#cccccc\"},\n        \"3,1\", \"3,2\", \"3,3\", \"3,4\", \"3,5\", \"3,6\", \"3,7\", \"3,8\", \"3,9\", \"3,10\", \"3,11\",\n        {\"c\": \"#777777\", \"w\": 2.25},\n        \"3,13\\n\\n\\n0,0\",\n        {\"x\": 0.5, \"c\": \"#AAAAAA\"},\n        \"3,14\",\n        {\"x\": 0.25},\n        \"3,12\\n\\n\\n0,1\"\n      ],\n      [\n        {\"w\": 2.25},\n        \"4,0\\n\\n\\n1,0\",\n        {\"c\": \"#cccccc\"},\n        \"4,2\", \"4,3\", \"4,4\", \"4,5\", \"4,6\", \"4,7\", \"4,8\", \"4,9\", \"4,10\", \"4,11\",\n        {\"c\": \"#AAAAAA\", \"w\": 1.75},\n        \"4,12\",\n        {\"x\": 1.5},\n        \"4,14\"\n      ],\n      [\n        {\"y\": -0.75, \"x\": 14.25, \"c\": \"#777777\"},\n        \"4,13\"\n      ],\n      [\n        {\"y\": -0.25, \"c\": \"#AAAAAA\", \"w\": 1.25},\n        \"5,0\",\n        {\"w\": 1.25},\n        \"5,1\",\n        {\"w\": 1.25},\n        \"5,2\",\n        {\"w\": 6.25},\n        \"5,6\",\n        \"5,9\",\n        \"5,10\",\n        \"5,11\"\n      ],\n      [\n        {\"y\": -0.75, \"x\": 13.25, \"c\": \"#777777\"},\n        \"5,12\", \"5,13\", \"5,14\"\n      ],\n      [\n        {\"c\": \"#AAAAAA\", \"w\": 1.25},\n        \"4,0\\n\\n\\n1,1\",\n        \"4,1\\n\\n\\n1,1\"\n      ]\n    ]\n  }\n}"
